const [atual, anterior] = $input.all().map(i => i.json);

function n(v) {
  return Number(v ?? 0);
}

function variacao(a, b) {
  if (!isFinite(a) || !isFinite(b) || b === 0) return null;
  return ((a - b) / b) * 100;
}

function variacaoPP(a, b) {
  if (!isFinite(a) || !isFinite(b)) return null;
  return a - b;
}

function icone(v, menorMelhor = false) {
  if (v === null) return "➖";
  if (Math.abs(v) < 0.01) return "➖";

  if (menorMelhor) {
    return v < 0 ? "⬆️" : "⬇️";
  }

  return v > 0 ? "⬆️" : "⬇️";
}

function preparar(d) {

  d.investimento = n(d.investimento);

  d.impressoes = n(d.impressoes);
  d.cliques = n(d.cliques);
  d.clicks_all = n(d.clicks_all);
  d.visitas_pagina = n(d.visitas_pagina);
  d.leads = n(d.leads);

  d.ctr = n(d.ctr);
  d.cpc = n(d.cpc);
  d.cpm = n(d.cpm);

  d.connect_rate = n(d.connect_rate);
  d.conversao_lp = n(d.conversao_lp);
  d.conversao_forms = n(d.conversao_forms);

  d.custo_por_lead = n(d.custo_por_lead);

  return d;
}

const a = preparar(atual);
const b = preparar(anterior);

const camposPct = [
  "impressoes",
  "cliques",
  "clicks_all",
  "visitas_pagina",
  "leads",
  "investimento"
];

const camposMenorMelhor = [
  "cpc",
  "cpm",
  "custo_por_lead"
];

const camposPP = [
  "ctr",
  "connect_rate",
  "conversao_lp",
  "conversao_forms"
];

const comparativo = {};

// Crescimento (%)
for (const campo of camposPct) {

  const v = variacao(a[campo], b[campo]);

  comparativo[campo] = {
    variacao: v,
    icone: icone(v)
  };

}

// Menor é melhor
for (const campo of camposMenorMelhor) {

  const v = variacao(a[campo], b[campo]);

  comparativo[campo] = {
    variacao: v,
    icone: icone(v, true)
  };

}

// Diferença em pontos percentuais
for (const campo of camposPP) {

  const v = variacaoPP(a[campo], b[campo]);

  comparativo[campo] = {
    variacao_pp: v,
    icone: icone(v)
  };

}

return [{
  json: {
    atual: a,
    anterior: b,
    comparativo
  }
}];

