{{
(() => {

	const dados = $json;
	const linhas = [];

	function numero(valor, padrao = 0) {
		const convertido = Number(valor);
		return Number.isFinite(convertido) ? convertido : padrao;
	}

	function inteiro(valor) {
		return numero(valor).toLocaleString('pt-BR');
	}

	function decimal(valor, casas = 1) {
		return numero(valor)
			.toFixed(casas)
			.replace('.', ',');
	}

	function moeda(valor) {
		return numero(valor).toLocaleString('pt-BR', {
			minimumFractionDigits: 2,
			maximumFractionDigits: 2
		});
	}

	function limparNome(nome) {
		if (nome === 'TOTAL') {
			return 'TOTAL GOOGLE';
		}

		return nome
			.replace(/^(\[[^\]]+\]\s*)+/, '')
			.replace(/\s+\d{4}\.\d{2}\.\d{2}$/, '')
			.trim();
	}

	/**
	 * Formata comparações percentuais.
	 *
	 * - Campanha/métrica nova: 🆕 N/C
	 * - Ambos os períodos zerados: ➖ 0,0%
	 * - Comparação válida: ícone e percentual
	 */
	function comparacaoPercentual(
		comparativo,
		valorAtual,
		valorAnterior
	) {
		const atual = numero(valorAtual);
		const anterior = numero(valorAnterior);
		const variacao = comparativo?.variacao;

		if (variacao === null || variacao === undefined) {
			if (anterior === 0 && atual > 0) {
				return '🆕 N/C';
			}

			return '➖ 0,0%';
		}

		const variacaoNumerica = Number(variacao);

		if (!Number.isFinite(variacaoNumerica)) {
			return '➖ N/C';
		}

		const sinal = variacaoNumerica > 0 ? '+' : '';

		return `${comparativo?.icone ?? '➖'} ${sinal}${decimal(variacaoNumerica, 1)}%`;
	}

	function comparacaoPontosPercentuais(
		comparativo,
		valorAtual,
		valorAnterior,
		tolerancia = 0
	) {
		const atual = numero(valorAtual);
		const anterior = numero(valorAnterior);
		const diferenca = atual - anterior;

		let icone = comparativo?.icone;

		if (!icone) {
			icone =
				Math.abs(diferenca) <= tolerancia
					? '➖'
					: diferenca > 0
						? '⬆️'
						: '⬇️';
		}

		const sinal = diferenca > 0 ? '+' : '';

		return `${icone} ${sinal}${decimal(diferenca, 2)} pp`;
	}

	for (const [nome, campanha] of Object.entries(dados)) {
		if (
			!campanha ||
			typeof campanha !== 'object' ||
			!campanha.atual
		) {
			continue;
		}

		const atual = campanha.atual || {};
		const anterior = campanha.anterior || {};
		const comparativo = campanha.comparativo || {};

		const cliquesAtuais = numero(atual.cliques);
		const cliquesAnteriores = numero(anterior.cliques);

		const conversoesAtuais = numero(atual.conversoes);
		const conversoesAnteriores = numero(anterior.conversoes);

		const taxaAtual =
			cliquesAtuais > 0
				? (conversoesAtuais / cliquesAtuais) * 100
				: 0;

		const taxaAnterior =
			cliquesAnteriores > 0
				? (conversoesAnteriores / cliquesAnteriores) * 100
				: 0;

		let comparacaoTaxa;

		if (cliquesAnteriores === 0 && cliquesAtuais > 0) {
			comparacaoTaxa = '🆕 N/C';
		} else {
			const diferencaTaxa = taxaAtual - taxaAnterior;

			const iconeTaxa =
				Math.abs(diferencaTaxa) <= 2
					? '➖'
					: diferencaTaxa > 0
						? '⬆️'
						: '⬇️';

			const sinal = diferencaTaxa > 0 ? '+' : '';

			comparacaoTaxa =
				`${iconeTaxa} ${sinal}${decimal(diferencaTaxa, 1)} pp`;
		}

		const nomeLimpo = limparNome(nome);

		linhas.push(
`*FUNIL ${nomeLimpo}*
Gargalo: 🦆 | Está bom: 🦅
• Impressões: ${inteiro(atual.impressoes)} | ${comparacaoPercentual(
	comparativo.impressoes,
	atual.impressoes,
	anterior.impressoes
)}
• Cliques: ${inteiro(atual.cliques)} | ${comparacaoPercentual(
	comparativo.cliques,
	atual.cliques,
	anterior.cliques
)}
• CTR: ${decimal(atual.ctr, 2)}% | ${comparacaoPontosPercentuais(
	comparativo.ctr,
	atual.ctr,
	anterior.ctr,
	0.5
)} (${numero(atual.ctr) > 10 ? '🦅' : '🦆'})
• CPC: R$ ${moeda(atual.cpc)} | ${comparacaoPercentual(
	comparativo.cpc,
	atual.cpc,
	anterior.cpc
)} (${numero(atual.cpc, 999) < 5 ? '🦅' : '🦆'})
• CPM: R$ ${moeda(atual.cpm)} | ${comparacaoPercentual(
	comparativo.cpm,
	atual.cpm,
	anterior.cpm
)}
• Conversões: ${inteiro(atual.conversoes)} | ${comparacaoPercentual(
	comparativo.conversoes,
	atual.conversoes,
	anterior.conversoes
)}
• Taxa de Conversão: ${decimal(taxaAtual, 1)}% | ${comparacaoTaxa} (${taxaAtual > 10 ? '🦅' : '🦆'})
• Investimento: R$ ${moeda(atual.investimento)} | ${comparacaoPercentual(
	comparativo.investimento,
	atual.investimento,
	anterior.investimento
)}`
		);
	}

	return linhas.join('\n\n');

})()
}}

