const periodo = $('start end 2').first().json;

const inicioAtual = periodo.start_date || periodo.start;
const fimAtual = periodo.end_date || periodo.end;

const diasInformados = Number(periodo.dias);

const dias = Number.isFinite(diasInformados) && diasInformados > 0
	? diasInformados
	: diferencaDias(inicioAtual, fimAtual) + 1;

const inicioAnterior = subtrairDias(inicioAtual, dias);
const fimAnterior = subtrairDias(fimAtual, dias);

const entradas = $input.all().map(item => item.json);

const atualResp = entradas[0] || {};
const anteriorResp = entradas[1] || {};
const mesResp = entradas[2] || {};

const atual = Array.isArray(atualResp.results)
	? atualResp.results
	: [];

const anterior = Array.isArray(anteriorResp.results)
	? anteriorResp.results
	: [];

const investimentoMes = numero(
	mesResp.cost ?? numero(mesResp.costMicros) / 1e6
);

/**
 * Converte qualquer valor recebido em número.
 * Valores inválidos viram zero.
 */
function numero(valor) {
	const convertido = Number(valor);
	return Number.isFinite(convertido) ? convertido : 0;
}

/**
 * Calcula a quantidade de dias entre duas datas.
 */
function diferencaDias(inicio, fim) {
	if (!inicio || !fim) return 0;

	const dataInicio = criarDataUTC(inicio);
	const dataFim = criarDataUTC(fim);

	if (!dataInicio || !dataFim) return 0;

	return Math.floor(
		(dataFim.getTime() - dataInicio.getTime()) / 86400000
	);
}

/**
 * Cria uma data UTC a partir de YYYY-MM-DD.
 */
function criarDataUTC(data) {
	if (!data) return null;

	const partes = String(data).slice(0, 10).split('-').map(Number);

	if (partes.length !== 3 || partes.some(parte => !Number.isFinite(parte))) {
		return null;
	}

	const [ano, mes, dia] = partes;
	const resultado = new Date(Date.UTC(ano, mes - 1, dia));

	return Number.isNaN(resultado.getTime())
		? null
		: resultado;
}

/**
 * Subtrai uma quantidade de dias sem sofrer alteração de timezone.
 */
function subtrairDias(data, qtdDias) {
	const resultado = criarDataUTC(data);

	if (!resultado) return null;

	resultado.setUTCDate(
		resultado.getUTCDate() - numero(qtdDias)
	);

	return resultado.toISOString().slice(0, 10);
}

/**
 * Retorna a variação percentual.
 * Se o período anterior for zero, não existe base de comparação.
 */
function variacao(valorAtual, valorAnterior) {
	const a = numero(valorAtual);
	const b = numero(valorAnterior);

	if (b === 0) return null;

	return ((a - b) / b) * 100;
}

/**
 * Define a direção do indicador comparando valores absolutos.
 */
function direcao(
	valorAtual,
	valorAnterior,
	menorMelhor = false,
	tolerancia = 0
) {
	const a = Number(valorAtual);
	const b = Number(valorAnterior);

	if (!Number.isFinite(a) || !Number.isFinite(b)) {
		return '➖';
	}

	const diferenca = a - b;

	if (Math.abs(diferenca) <= tolerancia) {
		return '➖';
	}

	if (menorMelhor) {
		return diferenca < 0 ? '⬆️' : '⬇️';
	}

	return diferenca > 0 ? '⬆️' : '⬇️';
}

/**
 * Define a direção com base na variação percentual.
 */
function direcaoVariacao(
	valorAtual,
	valorAnterior,
	menorMelhor = false,
	toleranciaPercentual = 0
) {
	const percentual = variacao(valorAtual, valorAnterior);

	if (percentual === null) {
		return '➖';
	}

	return direcao(
		percentual,
		0,
		menorMelhor,
		toleranciaPercentual
	);
}

/**
 * Normaliza as métricas recebidas do Google Ads.
 */
function normalizarMetricas(campanha) {
	const metricas = campanha?.metrics || {};

	return {
		investimento: numero(metricas.costMicros) / 1e6,
		impressoes: numero(metricas.impressions),
		cliques: numero(metricas.clicks),
		conversoes: numero(metricas.conversions),
		todas_conversoes: numero(metricas.allConversions),
		valor_conversoes: numero(metricas.conversionsValue),
		valor_todas_conversoes: numero(metricas.allConversionsValue),

		cpm: numero(metricas.averageCpm) / 1e6,
		ctr: numero(metricas.ctr) * 100,
		cpc: numero(metricas.averageCpc) / 1e6
	};
}

/**
 * Cria uma campanha vazia para períodos em que ela não existia.
 */
function campanhaVazia(id, nome) {
	return {
		campaign: {
			id,
			name: nome
		},
		metrics: {}
	};
}

/**
 * Soma todas as campanhas de um período.
 */
function calcularTotais(campanhas) {
	const total = {
		investimento: 0,
		impressoes: 0,
		cliques: 0,
		conversoes: 0,
		todas_conversoes: 0,
		valor_conversoes: 0,
		valor_todas_conversoes: 0
	};

	for (const campanha of campanhas) {
		const metricas = normalizarMetricas(campanha);

		total.investimento += metricas.investimento;
		total.impressoes += metricas.impressoes;
		total.cliques += metricas.cliques;
		total.conversoes += metricas.conversoes;
		total.todas_conversoes += metricas.todas_conversoes;
		total.valor_conversoes += metricas.valor_conversoes;
		total.valor_todas_conversoes += metricas.valor_todas_conversoes;
	}

	total.ctr = total.impressoes > 0
		? (total.cliques / total.impressoes) * 100
		: 0;

	total.cpc = total.cliques > 0
		? total.investimento / total.cliques
		: 0;

	total.cpm = total.impressoes > 0
		? (total.investimento / total.impressoes) * 1000
		: 0;

	return total;
}

/**
 * Monta o objeto do período de uma campanha.
 */
function montarPeriodoCampanha(campanha, inicio, fim) {
	const metricas = normalizarMetricas(campanha);

	return {
		inicio,
		fim,

		id: campanha?.campaign?.id || null,
		nome: campanha?.campaign?.name || null,

		...metricas
	};
}

/**
 * Monta os comparativos entre dois períodos.
 */
function montarComparativo(a, b) {
	return {
		investimento: {
			variacao: variacao(a.investimento, b.investimento),
			icone: direcaoVariacao(
				a.investimento,
				b.investimento,
				false,
				10
			)
		},

		impressoes: {
			variacao: variacao(a.impressoes, b.impressoes),
			icone: direcao(a.impressoes, b.impressoes)
		},

		cliques: {
			variacao: variacao(a.cliques, b.cliques),
			icone: direcao(a.cliques, b.cliques)
		},

		ctr: {
			variacao_pp: a.ctr - b.ctr,
			icone: direcao(a.ctr, b.ctr, false, 0.5)
		},

		cpc: {
			variacao: variacao(a.cpc, b.cpc),
			icone: direcaoVariacao(
				a.cpc,
				b.cpc,
				true,
				5
			)
		},

		cpm: {
			variacao: variacao(a.cpm, b.cpm),
			icone: direcaoVariacao(
				a.cpm,
				b.cpm,
				true,
				5
			)
		},

		conversoes: {
			variacao: variacao(a.conversoes, b.conversoes),
			icone: direcao(a.conversoes, b.conversoes)
		},

		todas_conversoes: {
			variacao: variacao(
				a.todas_conversoes,
				b.todas_conversoes
			),
			icone: direcao(
				a.todas_conversoes,
				b.todas_conversoes
			)
		},

		valor_conversoes: {
			variacao: variacao(
				a.valor_conversoes,
				b.valor_conversoes
			),
			icone: direcao(
				a.valor_conversoes,
				b.valor_conversoes
			)
		},

		valor_todas_conversoes: {
			variacao: variacao(
				a.valor_todas_conversoes,
				b.valor_todas_conversoes
			),
			icone: direcao(
				a.valor_todas_conversoes,
				b.valor_todas_conversoes
			)
		}
	};
}

const campanhasAtuaisPorId = new Map(
	atual.map(campanha => [
		String(campanha.campaign.id),
		campanha
	])
);

const campanhasAnterioresPorId = new Map(
	anterior.map(campanha => [
		String(campanha.campaign.id),
		campanha
	])
);

/*
 * Inclui campanhas:
 * - presentes nos dois períodos;
 * - presentes somente no atual;
 * - presentes somente no anterior.
 */
const idsCampanhas = new Set([
	...campanhasAtuaisPorId.keys(),
	...campanhasAnterioresPorId.keys()
]);

const resultado = {};

for (const id of idsCampanhas) {
	const campanhaAtualOriginal = campanhasAtuaisPorId.get(id);
	const campanhaAnteriorOriginal = campanhasAnterioresPorId.get(id);

	const nome =
		campanhaAtualOriginal?.campaign?.name ||
		campanhaAnteriorOriginal?.campaign?.name ||
		id;

	const campanhaAtual = campanhaAtualOriginal ||
		campanhaVazia(id, nome);

	const campanhaAnterior = campanhaAnteriorOriginal ||
		campanhaVazia(id, nome);

	const dadosAtuais = montarPeriodoCampanha(
