function variacao(valorAtual, valorAnterior) {
	const a = numero(valorAtual);
	const b = numero(valorAnterior);

	if (b === 0) return null;

	return ((a - b) / b) * 100;
}

/**
 * Define a direção do indicador comparando valores absolutos.
 */
function direcao(
	valorAtual,
	valorAnterior,
	menorMelhor = false,
	tolerancia = 0
) {
	const a = Number(valorAtual);
	const b = Number(valorAnterior);

	if (!Number.isFinite(a) || !Number.isFinite(b)) {
		return '➖';
	}

	const diferenca = a - b;

	if (Math.abs(diferenca) <= tolerancia) {
