			),
			icone: direcao(
				a.valor_todas_conversoes,
				b.valor_todas_conversoes
			)
		}
	};
}

const campanhasAtuaisPorId = new Map(
	atual.map(campanha => [
		String(campanha.campaign.id),
		campanha
	])
);

const campanhasAnterioresPorId = new Map(
	anterior.map(campanha => [
		String(campanha.campaign.id),
		campanha
	])
);

/*
 * Inclui campanhas:
 * - presentes nos dois períodos;
 * - presentes somente no atual;
 * - presentes somente no anterior.
 */
const idsCampanhas = new Set([
	...campanhasAtuaisPorId.keys(),
	...campanhasAnterioresPorId.keys()
]);

const resultado = {};

for (const id of idsCampanhas) {
	const campanhaAtualOriginal = campanhasAtuaisPorId.get(id);
	const campanhaAnteriorOriginal = campanhasAnterioresPorId.get(id);

	const nome =
		campanhaAtualOriginal?.campaign?.name ||
		campanhaAnteriorOriginal?.campaign?.name ||
		id;

	const campanhaAtual = campanhaAtualOriginal ||
		campanhaVazia(id, nome);

	const campanhaAnterior = campanhaAnteriorOriginal ||
		campanhaVazia(id, nome);

	const dadosAtuais = montarPeriodoCampanha(
		campanhaAtual,
		inicioAtual,
		fimAtual
	);

	const dadosAnteriores = montarPeriodoCampanha(
		campanhaAnterior,
		inicioAnterior,
		fimAnterior
	);

	/*
	 * Evita sobrescrever campanhas caso duas tenham o mesmo nome.
	 */
	const chave = resultado[nome]
		? `${nome} [${id}]`
		: nome;

	resultado[chave] = {
		atual: dadosAtuais,
		anterior: dadosAnteriores,
		comparativo: montarComparativo(
			dadosAtuais,
			dadosAnteriores
		)
	};
}

/*
 * Os totais são calculados separadamente.
 * Assim, nenhuma campanha é ignorada.
 */
const totalAtual = calcularTotais(atual);
const totalAnterior = calcularTotais(anterior);

resultado.TOTAL = {
	atual: {
		inicio: inicioAtual,
		fim: fimAtual,
		investimento_mes: investimentoMes,
		...totalAtual
	},

	anterior: {
		inicio: inicioAnterior,
		fim: fimAnterior,
		...totalAnterior
	},

	comparativo: montarComparativo(
		totalAtual,
		totalAnterior
	)
};

return [
	{
		json: resultado
	}
];
